!function(){const e=document.querySelectorAll(".reveal-on-scroll");if(!e.length)return;if(!("IntersectionObserver"in window))return void e.forEach(e=>e.classList.add("is-visible"));const r=new IntersectionObserver(e=>{e.forEach(e=>{e.isIntersecting&&(e.target.classList.add("is-visible"),r.unobserve(e.target))})},{rootMargin:"0px 0px -10% 0px",threshold:.05});e.forEach(e=>r.observe(e))}();